const packet =
  "";

const SESSION_IV_LABEL = "6372797074696e675f73657373696f6e6976"; // crypting_sessioniv
const SESSION_KEY_LABEL = "6372797074696e675f73657373696f6e6b6579"; // crypting_sessionkey

const ivIndex = packet.indexOf(SESSION_IV_LABEL);
console.log(`IV Label Index: ${ivIndex}`);

if (ivIndex !== -1) {
  const afterIv = packet.substring(
    ivIndex + SESSION_IV_LABEL.length,
    ivIndex + SESSION_IV_LABEL.length + 50,
  );
  console.log(`Data after IV Label: ${afterIv}`);
}

const keyIndex = packet.indexOf(SESSION_KEY_LABEL);
console.log(`Key Label Index: ${keyIndex}`);

// Look for Key Value.
// Usually Key is BEFORE the Label? Or AFTER?
// Let's check surroundings of Key Label.
if (keyIndex !== -1) {
  const beforeKey = packet.substring(Math.max(0, keyIndex - 100), keyIndex);
  console.log(`Data before Key Label: ${beforeKey}`);

  // Look for identifier "13 20" (String 32)
  const keyMarkerIndex = beforeKey.lastIndexOf("1320");
  console.log(`1320 Marker in preceding data: ${keyMarkerIndex}`);
  if (keyMarkerIndex !== -1) {
    console.log(`Potential Key Data: ${beforeKey.substring(keyMarkerIndex)}`);
  }
}
